import{_ as r,o as e,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Q-G02: 董事高階經理人異動審計 - hr-performance-reviewer 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/4967_十銓/20260429/G02_董事高階經理人異動審計_績效管理專家.md","filePath":"審計報告庫/經營審計/4967_十銓/20260429/G02_董事高階經理人異動審計_績效管理專家.md"}'),o={name:"審計報告庫/經營審計/4967_十銓/20260429/G02_董事高階經理人異動審計_績效管理專家.md"};function l(n,a,s,h,c,_){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="q-g02-董事高階經理人異動審計-hr-performance-reviewer-審計報告" tabindex="-1">Q-G02: 董事高階經理人異動審計 - hr-performance-reviewer 審計報告 <a class="header-anchor" href="#q-g02-董事高階經理人異動審計-hr-performance-reviewer-審計報告" aria-label="Permalink to &quot;Q-G02: 董事高階經理人異動審計 - hr-performance-reviewer 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：經營層穩定，財務職能轉型。</li><li><strong>風險評級</strong>：低至中（交接期合規風險）。</li><li><strong>量化指標</strong>：核心異動 0%；交接期約 120 天。</li><li><strong>數據時效</strong>：截至 2026 年 4 月。</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>核心穩定</strong>：董事長與總經理任期內無變動。</li><li><strong>職能異動</strong>：2024 年 8 月財務長轉任特助。</li><li><strong>權力結構</strong>：2024 年完成董事改選，強化管理。</li><li><strong>留任指標</strong>：高管平均留任 5.2 年；磨合期 4 個月。</li><li><strong>診斷見解</strong>：公司正從「專業經理人主導」轉向「核心團隊深度介入」。2024 年財務職能集體異動反映了權力架構重新分配。雖然管理層穩定，但財務職能「內部化」可能導致未來內控壓力增加。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="核心關鍵位階審核" tabindex="-1">[核心關鍵位階審核] <a class="header-anchor" href="#核心關鍵位階審核" aria-label="Permalink to &quot;[核心關鍵位階審核]&quot;">​</a></h3><ul><li><strong>核心重點</strong>：董事長、總經理職位極度穩定；財務主管（CFO層級）發生重大轉向。</li><li><strong>深度見解</strong>：2024 年 8 月的異動顯示，原財務長彭大維（兼發言人）卸任核心職能轉任董事長特助，這是一種典型的「權力回流」行為。新任財務主管（陳芊樺）與會計主管（李家宜）均為內部晉升，顯示公司正強化內部管理鏈的垂直控制力。</li></ul><h3 id="非正常時點與風險偵測" tabindex="-1">[非正常時點與風險偵測] <a class="header-anchor" href="#非正常時點與風險偵測" aria-label="Permalink to &quot;[非正常時點與風險偵測]&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年 8 月的集體異動與 2024 年股東會後的組織重組高度同步。</li><li><strong>深度見解</strong>：此類異動並非發生在財報發布前夕的「逃避式離職」，而是配合股東會後的組織架構調整。雖然看似有序，但「財務長」職位在公告中未明確指派繼任者（僅由財務經理/會計經理接手），顯示公司在專業化與家族管理之間進行權力平衡，短期內可能面臨財務決策效率的磨合。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：財務職能弱化風險</strong>。原財務長（彭大維）卸任核心職責轉為特助，代表公司正將財務權力從「專業經理人」收回至「董事長辦公室」。若新任財務團隊缺乏足夠的專業深度或獨立性，可能導致未來在重大投資決策與合規審計上的風險上升。</li><li><strong>空頭風險二：治理結構透明度挑戰</strong>。2024 年董事會改選後，核心成員（如夏紹安）與管理層職務重疊度增加。雖然確保了執行力，但對於獨立董事的監督效能以及「家族治理」與「專業管理」的平衡提出了挑戰。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>MOPS 重大訊息</strong>: OK (2024/08/01 職務調整公告、2024/06/19 董事改選紀錄)</li><li><strong>年報/財務報告</strong>: OK (2023-2025 簽署人比對)</li><li><strong>關鍵核對碼</strong>: 2024/08/01 決議：原財務長彭大維轉任董事長特助；新任財務主管陳芊樺、會計主管李家宜。</li></ul>',16)])])}const u=r(o,[["render",l]]);export{g as __pageData,u as default};
